#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* arr = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int* freq = (int*) calloc(10001, sizeof(int));
        for (int i = 0; i < N; i++) {
            freq[arr[i]]++;
        }
        int sum = 0;
        for (int i = 0; i < 10001; i++) {
            if (freq[i] == K) {
                sum += i;
            }
        }
        if (sum == 0) {
            printf("-1\n");
        } else {
            printf("%d\n", sum);
        }
        free(arr);
        free(freq);
    }
    return 0;
}

