    int T;
    cin >> T;
    while (T--) {
        int N, K;
        cin >> N >> K;
        unordered_map<int, int> freq;
        for (int i = 0; i < N; i++) {
            int x;
            cin >> x;
            freq[x]++;
        }
        int sum = 0;
        for (auto& it : freq) {
            if (it.second == K) {
                sum += it.first;
            }
        }
        if (sum == 0) {
            cout << -1 << endl;
        } else {
            cout << sum << endl;
        }
    }
    return 0;
}

